/* Test driver */
public class Main {
    public static void main(String[] args) {
        AuctionSystem sys = new AuctionSystem();
        Bidder a = sys.registerBidder("b1", "Alice");
        Bidder b = sys.registerBidder("b2", "Bob");
        Item w = new Item("i1", "Watch", "x", 100.0);
        Auction au = sys.createAuction("a1", w, 100.0, 10.0, new WinnerStrategy.HighestBidStrategy());
        au.start();
        au.placeBid(a, 150.0);
        au.placeBid(b, 200.0);
        au.placeBid(a, 250.0);
        if (au.getCurrentHighestBid() == 250.0) System.out.println("OK_HIGHEST");
        WinnerStrategy.WinnerResult r = au.close();
        if (r != null && r.getWinner() == a && r.getWinningPrice() == 250.0) System.out.println("OK_WINNER");
    }
}

