/* Test driver */
public class Main {
    public static void main(String[] args) {
        AuctionSystem sys = new AuctionSystem();
        Bidder a = sys.registerBidder("b1", "A");
        Bidder b = sys.registerBidder("b2", "B");
        Item w = new Item("i1", "X", "x", 100.0);
        Auction au = sys.createAuction("a1", w, 100.0, 10.0, new WinnerStrategy.SecondPriceStrategy());
        au.start();
        au.placeBid(a, 150.0);
        au.placeBid(b, 200.0);
        au.placeBid(a, 300.0);
        WinnerStrategy.WinnerResult r = au.close();
        if (r != null && r.getWinner() == a && Math.abs(r.getWinningPrice() - 200.0) < 0.01) System.out.println("OK_SECOND_PRICE");
    }
}

